import{_ as o,c as s,o as d,a1 as i,j as e,a as l,t}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"Introducción: OpenCode Agent Skills | opencode-agent-skills","description":"Aprende el valor central y las principales funcionalidades de OpenCode Agent Skills. Domina el descubrimiento dinámico de habilidades, la inyección de contexto, la recuperación de compresión y otras características, con compatibilidad con Claude Code y recomendación automática.","frontmatter":{"title":"Introducción: OpenCode Agent Skills | opencode-agent-skills","sidebarTitle":"Skills que hacen que la IA te entienda","subtitle":"Introducción: OpenCode Agent Skills","description":"Aprende el valor central y las principales funcionalidades de OpenCode Agent Skills. Domina el descubrimiento dinámico de habilidades, la inyección de contexto, la recuperación de compresión y otras características, con compatibilidad con Claude Code y recomendación automática.","tags":["Guía de inicio","Introducción del plugin"],"prerequisite":[],"order":1},"headers":[],"relativePath":"es/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md","filePath":"es/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"}'),c={name:"es/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"},r={tabindex:"0"};function u(n,a,p,m,h,b){return d(),s("div",null,[a[7]||(a[7]=i(`<h1 id="¿que-es-opencode-agent-skills" tabindex="-1">¿Qué es OpenCode Agent Skills? <a class="header-anchor" href="#¿que-es-opencode-agent-skills" aria-label="Permalink to &quot;¿Qué es OpenCode Agent Skills?&quot;">​</a></h1><h2 id="lo-que-podras-hacer-despues-de-completar-esta-leccion" tabindex="-1">Lo que podrás hacer después de completar esta lección <a class="header-anchor" href="#lo-que-podras-hacer-despues-de-completar-esta-leccion" aria-label="Permalink to &quot;Lo que podrás hacer después de completar esta lección&quot;">​</a></h2><ul><li>Conocer el valor central del plugin OpenCode Agent Skills</li><li>Dominar las principales funcionalidades del plugin</li><li>Entender cómo se descubren y cargan automáticamente las habilidades</li><li>Diferenciar este plugin de otras soluciones de gestión de habilidades</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p>Es posible que hayas enfrentado estas situaciones:</p><ul><li><strong>Dificultad en la gestión dispersa de habilidades</strong>: Las habilidades se encuentran dispersas en múltiples ubicaciones como proyectos, directorios de usuario y caché de plugins, lo que dificulta encontrar la habilidad adecuada</li><li><strong>Las sesiones largas se vuelven problemáticas</strong>: Después de sesiones prolongadas, las habilidades cargadas previamente pueden volverse inválidas debido a la compresión del contexto</li><li><strong>Ansiedad por la compatibilidad</strong>: Preocupación de que las habilidades y plugins existentes no se puedan usar después de migrar desde Claude Code</li><li><strong>Configuración repetitiva</strong>: Cada proyecto requiere reconfigurar las habilidades, sin un mecanismo unificado de gestión</li></ul><p>Todos estos problemas están afectando tu eficiencia al usar asistentes de IA.</p><h2 id="idea-central" tabindex="-1">Idea central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea central&quot;">​</a></h2><p><strong>OpenCode Agent Skills</strong> es un sistema de plugins que proporciona capacidades de descubrimiento y gestión dinámica de habilidades para OpenCode.</p><div class="info custom-block"><p class="custom-block-title">¿Qué es una habilidad?</p><p>Una habilidad (Skill) es un módulo reutilizable que contiene guías de flujo de trabajo para la IA. Típicamente es un directorio que contiene un archivo <code>SKILL.md</code> (que describe la funcionalidad y el uso de la habilidad), junto con posibles archivos complementarios (documentos, scripts, etc.).</p></div><p><strong>Valor central</strong>: Mediante la estandarización del formato de habilidades (SKILL.md), se logra la reutilización de habilidades entre proyectos y sesiones.</p><h3 id="arquitectura-tecnica" tabindex="-1">Arquitectura técnica <a class="header-anchor" href="#arquitectura-tecnica" aria-label="Permalink to &quot;Arquitectura técnica&quot;">​</a></h3><p>El plugin está desarrollado con TypeScript + Bun + Zod, proporcionando 4 herramientas centrales:</p><table tabindex="0"><thead><tr><th>Herramienta</th><th>Función</th></tr></thead><tbody><tr><td><code>use_skill</code></td><td>Inyecta el contenido del SKILL.md de la habilidad al contexto de la sesión</td></tr><tr><td><code>read_skill_file</code></td><td>Lee los archivos soportados dentro del directorio de la habilidad (documentos, configuración, etc.)</td></tr><tr><td><code>run_skill_script</code></td><td>Ejecuta scripts ejecutables en el contexto del directorio de la habilidad</td></tr><tr><td><code>get_available_skills</code></td><td>Obtiene la lista de habilidades actualmente disponibles</td></tr></tbody></table><h2 id="principales-funcionalidades" tabindex="-1">Principales funcionalidades <a class="header-anchor" href="#principales-funcionalidades" aria-label="Permalink to &quot;Principales funcionalidades&quot;">​</a></h2><h3 id="_1-descubrimiento-dinamico-de-habilidades" tabindex="-1">1. Descubrimiento dinámico de habilidades <a class="header-anchor" href="#_1-descubrimiento-dinamico-de-habilidades" aria-label="Permalink to &quot;1. Descubrimiento dinámico de habilidades&quot;">​</a></h3><p>El plugin descubre automáticamente habilidades desde múltiples ubicaciones, ordenadas por prioridad:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. .opencode/skills/              (nivel de proyecto - OpenCode)</span></span>
<span class="line"><span>2. .claude/skills/                (nivel de proyecto - Claude Code)</span></span>
<span class="line"><span>3. ~/.config/opencode/skills/     (nivel de usuario - OpenCode)</span></span>
<span class="line"><span>4. ~/.claude/skills/              (nivel de usuario - Claude Code)</span></span>
<span class="line"><span>5. ~/.claude/plugins/cache/       (caché de plugins)</span></span>
<span class="line"><span>6. ~/.claude/plugins/marketplaces/ (plugins instalados)</span></span></code></pre></div><p><strong>Regla</strong>: La primera habilidad coincidente tiene efecto, las habilidades posteriores con el mismo nombre son ignoradas.</p><blockquote><p>¿Por qué está diseñado así?</p><p>Las habilidades a nivel de proyecto tienen prioridad sobre las a nivel de usuario, lo que te permite personalizar comportamientos específicos en proyectos sin afectar la configuración global.</p></blockquote><h3 id="_2-inyeccion-de-contexto" tabindex="-1">2. Inyección de contexto <a class="header-anchor" href="#_2-inyeccion-de-contexto" aria-label="Permalink to &quot;2. Inyección de contexto&quot;">​</a></h3><p>Cuando llamas a <code>use_skill</code>, el contenido de la habilidad se inyecta en el contexto de la sesión en formato XML:</p><ul><li><code>noReply: true</code> - La IA no responderá al mensaje inyectado</li><li><code>synthetic: true</code> - Marcado como mensaje generado por el sistema (no se muestra en la UI, no cuenta como entrada del usuario)</li></ul><p>Esto significa que el contenido de la habilidad persistirá en el contexto de la sesión, y las habilidades seguirán estando disponibles incluso cuando la sesión crezca y ocurra compresión del contexto.</p><h3 id="_3-mecanismo-de-recuperacion-de-compresion" tabindex="-1">3. Mecanismo de recuperación de compresión <a class="header-anchor" href="#_3-mecanismo-de-recuperacion-de-compresion" aria-label="Permalink to &quot;3. Mecanismo de recuperación de compresión&quot;">​</a></h3><p>Cuando OpenCode ejecuta compresión del contexto (una operación común en sesiones largas), el plugin escucha el evento <code>session.compacted</code> y reinyecta automáticamente la lista de habilidades disponibles.</p><p>Esto asegura que la IA siempre sepa qué habilidades están disponibles durante sesiones largas, sin perder la capacidad de acceder a las habilidades debido a la compresión.</p><h3 id="_4-compatibilidad-con-claude-code" tabindex="-1">4. Compatibilidad con Claude Code <a class="header-anchor" href="#_4-compatibilidad-con-claude-code" aria-label="Permalink to &quot;4. Compatibilidad con Claude Code&quot;">​</a></h3><p>El plugin es completamente compatible con el sistema de habilidades y plugins de Claude Code, soportando:</p><ul><li>Habilidades de Claude Code (<code>.claude/skills/&lt;skill-name&gt;/SKILL.md</code>)</li><li>Caché de plugins de Claude (<code>~/.claude/plugins/cache/...</code>)</li><li>Mercado de plugins de Claude (<code>~/.claude/plugins/marketplaces/...</code>)</li></ul><p>Esto significa que si usabas Claude Code anteriormente, puedes seguir usando tus habilidades y plugins existentes después de migrar a OpenCode.</p><h3 id="_5-recomendacion-automatica-de-habilidades" tabindex="-1">5. Recomendación automática de habilidades <a class="header-anchor" href="#_5-recomendacion-automatica-de-habilidades" aria-label="Permalink to &quot;5. Recomendación automática de habilidades&quot;">​</a></h3><p>El plugin monitorea tus mensajes y utiliza similitud semántica para detectar si están relacionados con alguna habilidad disponible:</p><ul><li>Calcula el vector embedding del mensaje</li><li>Calcula la similitud del coseno con las descripciones de todas las habilidades</li><li>Cuando la similitud supera el umbral, inyecta un prompt de evaluación sugiriendo a la IA cargar la habilidad relacionada</li></ul><p>Este proceso es completamente automático, no necesitas recordar nombres de habilidades ni solicitarlas explícitamente.</p><h3 id="_6-integracion-con-superpowers-opcional" tabindex="-1">6. Integración con Superpowers (opcional) <a class="header-anchor" href="#_6-integracion-con-superpowers-opcional" aria-label="Permalink to &quot;6. Integración con Superpowers (opcional)&quot;">​</a></h3><p>El plugin soporta flujos de trabajo de Superpowers, habilitado mediante variables de entorno:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opencode</span></span></code></pre></div><p>Una vez habilitado, el plugin detectará automáticamente la habilidad <code>using-superpowers</code> e inyectará la guía completa del flujo de trabajo durante la inicialización de la sesión.</p><h2 id="comparacion-con-otras-soluciones" tabindex="-1">Comparación con otras soluciones <a class="header-anchor" href="#comparacion-con-otras-soluciones" aria-label="Permalink to &quot;Comparación con otras soluciones&quot;">​</a></h2>`,40)),e("table",r,[a[6]||(a[6]=e("thead",null,[e("tr",null,[e("th",null,"Solución"),e("th",null,"Características"),e("th",null,"Escenario de aplicación")])],-1)),e("tbody",null,[a[3]||(a[3]=e("tr",null,[e("td",null,[e("strong",null,"opencode-agent-skills")]),e("td",null,"Descubrimiento dinámico, recuperación de compresión, recomendación automática"),e("td",null,"Escenarios que requieren gestión unificada y recomendación automática")],-1)),e("tr",null,[a[1]||(a[1]=e("td",null,[e("strong",null,"opencode-skills")],-1)),e("td",null,[a[0]||(a[0]=l("Registro automático como herramienta ",-1)),e("code",null,"skills_"+t(n.name),1)]),a[2]||(a[2]=e("td",null,"Escenarios que requieren llamadas de herramientas independientes",-1))]),a[4]||(a[4]=e("tr",null,[e("td",null,[e("strong",null,"superpowers")]),e("td",null,"Flujo de trabajo completo de desarrollo de software"),e("td",null,"Proyectos que requieren estándares estrictos de proceso")],-1)),a[5]||(a[5]=e("tr",null,[e("td",null,[e("strong",null,"skillz")]),e("td",null,"Modo servidor MCP"),e("td",null,"Escenarios que requieren usar habilidades entre herramientas")],-1))])]),a[8]||(a[8]=i('<p>Razones para elegir este plugin:</p><ul><li>✅ <strong>Cero configuración</strong>: Descubrimiento y gestión automática de habilidades</li><li>✅ <strong>Recomendación inteligente</strong>: Recomendación automática basada en coincidencia semántica</li><li>✅ <strong>Recuperación de compresión</strong>: Estable y confiable en sesiones largas</li><li>✅ <strong>Compatibilidad</strong>: Migración sin problemas de habilidades de Claude Code</li></ul><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de esta lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de esta lección&quot;">​</a></h2><p>El plugin OpenCode Agent Skills proporciona capacidades completas de gestión de habilidades para OpenCode a través de mecanismos centrales como descubrimiento dinámico, inyección de contexto y recuperación de compresión. Su valor central radica en:</p><ul><li><strong>Automatización</strong>: Reduce la carga de configuración manual y memorización de nombres de habilidades</li><li><strong>Estabilidad</strong>: Las habilidades siempre están disponibles durante sesiones largas</li><li><strong>Compatibilidad</strong>: Integración fluida con el ecosistema existente de Claude Code</li></ul><h2 id="avance-del-proxima-leccion" tabindex="-1">Avance del próxima lección <a class="header-anchor" href="#avance-del-proxima-leccion" aria-label="Permalink to &quot;Avance del próxima lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos <strong><a href="./../installation/">Instalar OpenCode Agent Skills</a></strong>.</p><p>Aprenderás:</p><ul><li>Cómo agregar el plugin en la configuración de OpenCode</li><li>Cómo verificar si el plugin está instalado correctamente</li><li>Configuración del modo de desarrollo local</li></ul></blockquote><hr><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del código fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para ver las ubicaciones del código fuente</strong></summary><blockquote><p>Tiempo de actualización：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del archivo</th><th>Líneas</th></tr></thead><tbody><tr><td>Entrada del plugin y resumen de funcionalidades</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L1-L12" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>1-12</td></tr><tr><td>Lista de funcionalidades principales</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/README.md#L5-L11" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>5-11</td></tr><tr><td>Prioridad de descubrimiento de habilidades</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L246" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-246</td></tr><tr><td>Inyección de mensajes sintéticos</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>Mecanismo de recuperación de compresión</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L151" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-151</td></tr><tr><td>Módulo de coincidencia semántica</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/embeddings.ts#L108-L135" target="_blank" rel="noreferrer"><code>src/embeddings.ts</code></a></td><td>108-135</td></tr></tbody></table><p><strong>Constantes clave</strong>:</p><ul><li><code>EMBEDDING_MODEL = &quot;Xenova/all-MiniLM-L6-v2&quot;</code>：Modelo de embedding utilizado</li><li><code>SIMILARITY_THRESHOLD = 0.35</code>：Umbral de similitud semántica</li><li><code>TOP_K = 5</code>：Límite superior de habilidades devueltas en recomendación automática</li></ul><p><strong>Funciones clave</strong>:</p><ul><li><code>discoverAllSkills()</code>：Descubre habilidades desde múltiples ubicaciones</li><li><code>use_skill()</code>：Inyecta el contenido de la habilidad al contexto de la sesión</li><li><code>matchSkills()</code>：Coincide habilidades relacionadas basándose en similitud semántica</li><li><code>injectSyntheticContent()</code>：Inyecta contenido sintético a la sesión</li></ul></details>',10))])}const f=o(c,[["render",u]]);export{k as __pageData,f as default};
